/* eslint-disable */
// @ts-nocheck
import { applyParamsToScript, cborToScript } from "@blaze-cardano/uplc";
import { type Script } from "@blaze-cardano/core";
import { Type, Exact, TPlutusData } from "@blaze-cardano/data";
import { type PlutusData } from "@blaze-cardano/core";
type Data = PlutusData;
type Int = bigint;
type ByteArray = string;
type PolicyId = string;
type ScriptHash = string;
export type OutputReference = { output_index: bigint; transaction_id: string };

const Contracts = Type.Module({
  String: Type.String(),
  Anchor: Type.Object(
    {
      url: Type.Ref("String"),
      hash: Type.String(),
    },
    { ctor: 0n },
  ),
  Credential: Type.Union([
    Type.Object({
      VerificationKeyCredential: Type.Tuple([Type.String()], { ctor: 0n }),
    }),
    Type.Object({
      ScriptCredential: Type.Tuple([Type.String()], { ctor: 1n }),
    }),
  ]),
  Rational: Type.Object({
    numerator: Type.BigInt(),
    denominator: Type.BigInt(),
  }, { ctor: 0n }),
  GovernanceActionId: Type.Object({
    transaction: Type.String(),
    proposalProcedure: Type.BigInt(),
  }, { ctor: 0n }),
  GovernanceAction: Type.Union([
    Type.Object(
      {
        ProtocolParameters: Type.Object({
          ancestor: Type.Optional(Type.Ref("GovernanceActionId")),
          newParameters: Type.Object({
            ProtocolParametersUpdate: Type.Object({
              inner: Type.Array(Type.Tuple([Type.BigInt(), TPlutusData])),
            }),
          }),
          guardrails: Type.Optional(Type.String()),
        }, { ctor: 0n }),
      },
    ),
    Type.Object(
      {
        HardFork: Type.Object({
          ancestor: Type.Optional(Type.Ref("GovernanceActionId")),
          newVersion: Type.Object({
            ProtocolVersion: Type.Object({
              major: Type.BigInt(),
              minor: Type.BigInt(),
            }),
          }, { ctor: 0n }),
        },  { ctor: 1n }),
      },
    ),
    Type.Object(
      {
        TreasuryWithdrawal: Type.Object({
          beneficiaries: Type.Array(
            Type.Tuple([Type.Ref("Credential"), Type.BigInt()]),
          ),
          guardrails: Type.Optional(Type.String()),
        }, { ctor: 2n }),
      },
    ),
    Type.Object(
      {
        NoConfidence: Type.Object({
          ancestor: Type.Optional(Type.Ref("GovernanceActionId")),
        }, { ctor: 3n }),
      },

    ),
    Type.Object(
      {
        ConsitutionalCommittee: Type.Object({
          ancestor: Type.Optional(Type.Ref("GovernanceActionId")),
          evictedMembers: Type.Array(Type.Ref("Credential")),
          addedMembers: Type.Array(
            Type.Tuple([Type.Ref("Credential"), Type.BigInt()]),
          ),
          quorum: Type.Ref("Rational"),
        }, { ctor: 4n }),
      },
    ),
    Type.Object(
      {
        NewConstitution: Type.Object({
          ancestor: Type.Optional(Type.Ref("GovernanceActionId")),
          constitution: Type.Object({
            Constitution: Type.Object({
              guardRails: Type.Optional(Type.String()),
            }),
          }),
        }, { ctor: 5n }),
      },

    ),
    Type.Literal("NicePoll", { ctor: 6n }),
  ]),
  ProposalProcedure: Type.Object({
    deposit: Type.BigInt(),
    returnAddress: Type.Ref("Credential"),
    governanceAction: Type.Ref("GovernanceAction"),
  }, { ctor: 0n }),
  CosponsoredProposalProcedure: Type.Object({
    procedure: Type.Ref("ProposalProcedure"),
    anchor: Type.Ref("Anchor"),
  }, { ctor: 0n }),
  CosponsorDatum: Type.Union([
    Type.Object(
      {
        Before: Type.Object({
          cosponsored: Type.Ref("CosponsoredProposalProcedure"),
        }, { ctor: 0n }),
      },
    ),
    Type.Literal("After", { ctor: 1n }),
  ]),
  CosponsorMintRedeemer: Type.Union([
    Type.Literal("MDeposit", { ctor: 0n }),
    Type.Object({
      MRedeem: Type.Object({
          proof: Type.Array(
            Type.Union([
              Type.Object({
                Branch: Type.Object(
                  {
                    skip: Type.BigInt(),
                    neighbors: Type.String(),
                  },
                  { ctor: 0n },
                ),
              }),
              Type.Object({
                Fork: Type.Object(
                  {
                    skip: Type.BigInt(),
                    neighbor: Type.Object(
                      {
                        nibble: Type.BigInt(),
                        prefix: Type.String(),
                        root: Type.String(),
                      },
                      { ctor: 0n },
                    ),
                  },
                  { ctor: 1n },
                ),
              }),
              Type.Object({
                Leaf: Type.Object(
                  {
                    skip: Type.BigInt(),
                    key: Type.String(),
                    value: Type.String(),
                  },
                  { ctor: 2n },
                ),
              }),
            ]),
          ),
          expiredProposals: Type.Record(Type.String(), Type.BigInt()),
        },
        { ctor: 1n },
      ),
    }),
  ]),
  CosponsorWithdrawRedeemer: Type.Union([
    Type.Literal("WAggregate", { ctor: 0n }),
    Type.Object({
      WPropose: Type.Object(
        {
          collateralInputs: Type.String(),
          collateralOutput: Type.String(),
          collateralFee: Type.String(),
        },
        { ctor: 1n },
      ),
    }),
    Type.Literal("WWithdraw", { ctor: 2n }),
  ]),
  CosponsorStateDatum: Type.Object(
    {
      expiredProposalsMpfRoot: Type.String(),
    },
    { ctor: 0n },
  ),
  CosponsorStateRedeemer: Type.Object(
    {
      proof: Type.Array(
        Type.Union([
          Type.Object({
            Branch: Type.Object(
              {
                skip: Type.BigInt(),
                neighbors: Type.String(),
              },
              { ctor: 0n },
            ),
          }),
          Type.Object({
            Fork: Type.Object(
              {
                skip: Type.BigInt(),
                neighbor: Type.Object(
                  {
                    nibble: Type.BigInt(),
                    prefix: Type.String(),
                    root: Type.String(),
                  },
                  { ctor: 0n },
                ),
              },
              { ctor: 1n },
            ),
          }),
          Type.Object({
            Leaf: Type.Object(
              {
                skip: Type.BigInt(),
                key: Type.String(),
                value: Type.String(),
              },
              { ctor: 2n },
            ),
          }),
        ]),
      ),
      anchorList: Type.Array(Type.Ref("Anchor")),
    },
    { ctor: 0n },
  ),
});

export const String = Contracts.Import("String");
export type String = Exact<typeof String>;
export const Anchor = Contracts.Import("Anchor");
export type Anchor = Exact<typeof Anchor>;
export const Credential = Contracts.Import("Credential");
export type Credential = Exact<typeof Credential>;
export const Rational = Contracts.Import("Rational");
export type Rational = Exact<typeof Rational>;
export const GovernanceActionId = Contracts.Import("GovernanceActionId");
export type GovernanceActionId = Exact<typeof GovernanceActionId>;
export const GovernanceAction = Contracts.Import("GovernanceAction");
export type GovernanceAction = Exact<typeof GovernanceAction>;
export const ProposalProcedure = Contracts.Import("ProposalProcedure");
export type ProposalProcedure = Exact<typeof ProposalProcedure>;
export const CosponsoredProposalProcedure = Contracts.Import(
  "CosponsoredProposalProcedure",
);
export type CosponsoredProposalProcedure = Exact<
  typeof CosponsoredProposalProcedure
>;
export const CosponsorDatum = Contracts.Import("CosponsorDatum");
export type CosponsorDatum = Exact<typeof CosponsorDatum>;
export const CosponsorMintRedeemer = Contracts.Import("CosponsorMintRedeemer");
export type CosponsorMintRedeemer = Exact<typeof CosponsorMintRedeemer>;
export const CosponsorWithdrawRedeemer = Contracts.Import(
  "CosponsorWithdrawRedeemer",
);
export type CosponsorWithdrawRedeemer = Exact<typeof CosponsorWithdrawRedeemer>;
export const CosponsorStateDatum = Contracts.Import("CosponsorStateDatum");
export type CosponsorStateDatum = Exact<typeof CosponsorStateDatum>;
export const CosponsorStateRedeemer = Contracts.Import(
  "CosponsorStateRedeemer",
);
export type CosponsorStateRedeemer = Exact<typeof CosponsorStateRedeemer>;

